// ─── Load / Save ───
function loadState() {
  try {
    const saved = localStorage.getItem('vehiclehub_v5');
    if (saved) {
      const parsed = JSON.parse(saved);
      state = { ...state, ...parsed };
      if (!state.bills) state.bills = [];
      if (!state.downloadHistory) state.downloadHistory = [];
      if (!state.settings) {
        state.settings = {
          companyName: 'Vision Food & Packaging',
          companyCity: 'Lahore',
          companyAddress: 'Plot# 363, 364 & 366 Sunder Industrial Estate, Raiwind'
        };
      }
      if (!state.settings.username) state.settings.username = 'admin';
      if (!state.settings.password) state.settings.password = 'admin123';
      if (!state.settings.firebase) {
        state.settings.firebase = { apiKey: '', authDomain: '', databaseURL: '', projectId: '' };
      }
      if (state.settings.firebase && state.settings.firebase.databaseURL) {
        initFirebaseSync(state.settings.firebase);
      }

      // Migration: assign batchId to existing fuel entries
      state.fuel.forEach(f => {
        if (!f.batchId) f.batchId = f.id;
        if (!f.fuelType) f.fuelType = 'PETROL';
      });

      // Migration: create fuel bills for fuel entries that don't have one
      migrateFuelBills();
      
      // Migration: fuel bills should be Paid by default (paid at pump)
      // Also fix old random FUEL-xxx bill numbers to VFP-A-XX format
      let needsSave = false;
      state.bills.forEach(b => {
        if (b.fuelBatch) {
          // Mark old pending fuel bills as Paid
          if (b.status === 'Pending') {
            b.status = 'Paid';
            needsSave = true;
          }
          // Fix old random bill numbers (not VFP-A-XX format)
          if (b.billNo && !String(b.billNo).startsWith('VFP-A-')) {
            // Will be fixed when user opens the invoice (lazy migration)
            // Mark with a flag so we know it needs renumbering
            b._needsRenumber = true;
          }
        }
      });
      if (needsSave) saveState();
    }
    else seedDemoData();
    applyBranding();
  } catch(e) { 
    console.error("Error loading state:", e);
    seedDemoData(); 
  }
}

function saveState() {
  localStorage.setItem('vehiclehub_v5', JSON.stringify(state));
  
  // Robust Local Auto-Backup (protects against sudden wipes)
  try {
    const backupStr = localStorage.getItem('vehiclehub_v5_auto_backup');
    let shouldUpdateBackup = true;
    if (backupStr) {
      const backup = JSON.parse(backupStr);
      const oldVehicles = backup.vehicles ? backup.vehicles.length : 0;
      const newVehicles = state.vehicles ? state.vehicles.length : 0;
      
      // If we had vehicles before but now we have 0, DO NOT overwrite the backup
      if (oldVehicles > 0 && newVehicles === 0) {
        shouldUpdateBackup = false;
        console.warn("Auto-Backup protected: New state has 0 vehicles, keeping old backup!");
      }
    }
    if (shouldUpdateBackup) {
      localStorage.setItem('vehiclehub_v5_auto_backup', JSON.stringify(state));
    }
  } catch(e) {
    console.error("Auto backup failed:", e);
  }

  if (window.firebaseInitialized && window.firebaseDbRef) {
    window.firebaseDbRef.set(state);
  }
}

function migrateFuelBills() {
  if (!state.fuel || !state.bills) return;

  // Cleanup old incorrect individual migrated bills
  const oldMigratedCount = state.bills.filter(b => b.vendor === 'Fuel Entry (Migrated)').length;
  if (oldMigratedCount > 0) {
    state.bills = state.bills.filter(b => b.vendor !== 'Fuel Entry (Migrated)');
  }

  // Collect all fuel entry IDs that already have a bill
  const fuelIdsWithBill = new Set();
  state.bills.forEach(b => {
    if (b.fuelBatch && b.batchDetails) {
      b.batchDetails.forEach(d => fuelIdsWithBill.add(d.id));
    }
    if (b.type === 'Fuel' && b.fuelEntryId) {
      fuelIdsWithBill.add(b.fuelEntryId);
    }
  });

  // Group unbilled entries by batchId
  const unbilledBatches = {};
  state.fuel.forEach(f => {
    if (fuelIdsWithBill.has(f.id)) return;
    const bid = f.batchId || f.id;
    if (!unbilledBatches[bid]) unbilledBatches[bid] = [];
    unbilledBatches[bid].push(f);
  });

  // Create one bill per batch
  let migrated = 0;
  Object.keys(unbilledBatches).forEach(bid => {
    const batchRows = unbilledBatches[bid];
    const firstDate = batchRows[0].date;
    const grandTotal = batchRows.reduce((s, r) => s + Number(r.cost), 0);
    const billNo = generateNextBillNo();
    
    const voucherLines = batchRows.map(r => {
      const rate = r.rate || (r.litres > 0 ? (r.cost / r.litres) : 0);
      const vn = state.vehicles.find(v => v.id === r.vehicle)?.name || 'Unknown';
      return `${vn}: ${r.litres}L × PKR ${parseFloat(rate).toFixed(2)}/L = PKR ${Number(r.cost).toLocaleString()}`;
    }).join(' | ');

    const fuelBill = {
      id: bid, // use batchId as bill id
      billNo,
      date: firstDate,
      vehicle: batchRows[0].vehicle, // primary vehicle
      type: 'Fuel',
      vendor: `Fuel Voucher (${batchRows.length} Vehicle${batchRows.length > 1 ? 's' : ''})`,
      amount: grandTotal,
      status: 'Paid',
      notes: voucherLines,
      fuelBatchId: bid,
      fuelBatch: true,
      batchDetails: batchRows
    };
    state.bills.push(fuelBill);
    migrated++;
  });

  if (oldMigratedCount > 0 || migrated > 0) saveState();
}

