// ─── Navigation ───
function navigate(page) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  document.getElementById('page-' + page).classList.add('active');
  const navEl = document.getElementById('nav-' + page);
  if (navEl) navEl.classList.add('active');
  document.getElementById('topbarTitle').textContent = {
    dashboard: 'Dashboard', vehicles: 'Vehicles',
    drivers: 'Drivers', maintenance: 'Maintenance',
    fuel: 'Fuel Log', reports: 'Reports',
    departments: 'Departments', bills: 'Bill View',
    settings: 'System Settings', tokentax: 'Token & Tax'
  }[page] || page;
  renderPage(page);
  // Close sidebar on mobile
  if (window.innerWidth <= 900) {
    document.getElementById('sidebar').classList.remove('open');
  }
}

function renderPage(page) {
  if (page === 'dashboard')   renderDashboard();
  if (page === 'vehicles')    renderVehicles();
  if (page === 'bikes')       renderBikes();
  if (page === 'drivers')     renderDrivers();
  if (page === 'maintenance') renderMaintenance();
  if (page === 'fuel')        renderFuel();
  if (page === 'reports')     renderReports();
  if (page === 'bills') {
    renderBills();
    renderDownloadHistory();
  }
  if (page === 'departments') renderDepartments();
  if (page === 'settings')    renderSettings();
  if (page === 'tokentax')    renderTokenTax();
  renderSidebarDeptVehicles();
}

// ─── Helpers ───
function getDriverName(id) {
  const d = state.drivers.find(x => x.id === id);
  return d ? d.name : '—';
}
function getVehicleName(id) {
  const v = state.vehicles.find(x => x.id === id);
  return v ? v.name : '—';
}
function statusBadge(s) {
  const map = {
    'Active':'green','Idle':'blue','Maintenance':'orange',
    'Completed':'green','Pending':'orange','In Progress':'blue'
  };
  return `<span class="badge badge-${map[s]||'purple'}">${s}</span>`;
}
function formatDate(d) { return d ? new Date(d).toLocaleDateString('en-PK') : '—'; }

function generateNextBillNo() {
  if (!state.bills) state.bills = [];
  let maxNum = 0;
  state.bills.forEach(b => {
    if (b.billNo && String(b.billNo).startsWith('VFP-A-')) {
      const num = parseInt(String(b.billNo).replace('VFP-A-', ''), 10);
      if (!isNaN(num) && num > maxNum) {
        maxNum = num;
      }
    }
  });
  const nextNum = maxNum + 1;
  return `VFP-A-${String(nextNum).padStart(2, '0')}`;
}

function renderTokenTax() {
  const search = (document.getElementById('tokentaxSearch')?.value || '').toLowerCase();
  const tbody = document.getElementById('tokentaxBody');
  if (!tbody) return;

  const filtered = state.vehicles.filter(v => {
    // Show vehicles > 1000 CC (parse from power field e.g. "1300 CC" or "1800")
    const ccVal = parseInt((v.power || '').toString().replace(/[^0-9]/g, '')) || 0;
    const isOver1000cc = ccVal > 1000;
    const matchesSearch = !search || v.plate.toLowerCase().includes(search) || v.name.toLowerCase().includes(search);
    return isOver1000cc && matchesSearch;
  });

  tbody.innerHTML = filtered.length ? filtered.map((v, i) => {
    const deptAllot = state.allotments.find(a => a.vehicle === v.id && a.status === 'Active');
    const vDept = v.dept || (deptAllot ? deptAllot.department : '');
    const deptLabel = {
      general: 'General', scm: 'SCM', accounts: 'Accounts',
      sale: 'Sale', admin: 'Admin', production: 'Production'
    }[vDept] || vDept || 'General';

    const ccVal = parseInt((v.power || '').toString().replace(/[^0-9]/g, '')) || 0;
    return `
      <tr>
        <td>${i + 1}</td>
        <td><code style="background:var(--bg3);padding:2px 6px;border-radius:4px;font-size:0.8rem;">${v.plate || '-'}</code></td>
        <td><strong>${v.name || '-'}</strong></td>
        <td>${v.type || '-'}</td>
        <td><strong>${ccVal > 0 ? ccVal + ' CC' : v.power || '-'}</strong></td>
        <td><span class="dept-pill dept-${vDept || 'general'}">${deptLabel}</span></td>
        <td>${v.etag ? '<span class="status-badge active" style="background:#dcfce7;color:#15803d;padding:2px 8px;border-radius:4px;font-size:0.75rem;font-weight:600;">✅ Renewed</span>' : '<span style="color:var(--text-muted);font-size:0.75rem;">—</span>'}</td>
        <td>${v.envTag ? '<span class="status-badge active" style="background:#dcfce7;color:#15803d;padding:2px 8px;border-radius:4px;font-size:0.75rem;font-weight:600;">✅ Active</span>' : '<span style="color:var(--text-muted);font-size:0.75rem;">—</span>'}</td>
      </tr>
    `;
  }).join('') : `<tr><td colspan="8" style="text-align:center;padding:20px;color:var(--text-muted);">No vehicles above 1000 CC found</td></tr>`;
}
function fmtPKR(n) { return 'PKR ' + Number(n).toLocaleString('en-PK'); }

// ─── DASHBOARD ───
function renderDashboard() {
  document.getElementById('stat-total').textContent = state.vehicles.length;
  
  const bikeCount = state.vehicles.filter(v => v.type === 'Motorcycle').length;
  if (document.getElementById('stat-bikes')) document.getElementById('stat-bikes').textContent = bikeCount;
  
  const currentMonth = new Date().toISOString().slice(0, 7); // YYYY-MM
  const monthlyFuelCost = state.fuel.reduce((sum, f) => f.date.startsWith(currentMonth) ? sum + (f.cost || 0) : sum, 0);
  if (document.getElementById('stat-fuel-cost')) document.getElementById('stat-fuel-cost').textContent = fmtPKR(monthlyFuelCost);
  
  const pendingMaintenance = state.maintenance.filter(m => m.status === 'Pending').length;
  const maintenanceCount = pendingMaintenance > 0 ? pendingMaintenance : state.vehicles.filter(v => v.status === 'Maintenance').length;
  if (document.getElementById('stat-maintenance')) document.getElementById('stat-maintenance').textContent = maintenanceCount;

  // Recent vehicles table
  const tbody = document.getElementById('dashRecentBody');
  const recent = [...state.vehicles].slice(-5).reverse();
  tbody.innerHTML = recent.length ? recent.map(v => `
    <tr>
      <td><strong>${v.name}</strong></td>
      <td><code style="background:var(--bg3);padding:2px 8px;border-radius:6px;font-size:0.82rem;">${v.plate}</code></td>
      <td>${getDriverName(v.driver)}</td>
      <td>${statusBadge(v.status)}</td>
      <td>${getMostRecentService(v.id)}</td>
    </tr>
  `).join('') : `<tr><td colspan="5"><div class="empty-state"><div class="empty-icon">🚗</div><p>No vehicles yet</p></div></td></tr>`;

  drawStatusChart();
  drawFuelChart();
}

function getMostRecentService(vid) {
  const recs = state.maintenance.filter(m => m.vehicle === vid).sort((a,b) => new Date(b.date)-new Date(a.date));
  return recs.length ? formatDate(recs[0].date) : '—';
}

// ─── VEHICLES ───
function renderVehicles() {
  const statusF = document.getElementById('vehicleStatusFilter').value;
  const typeF   = document.getElementById('vehicleTypeFilter').value;
  const deptF   = document.getElementById('vehicleDeptFilter').value;
  const search  = document.getElementById('vehicleSearch').value.toLowerCase();
  
  let list = state.vehicles.filter(v => {
    const deptAllot = state.allotments.find(a => a.vehicle === v.id && a.status === 'Active');
    const vDept = v.dept || (deptAllot ? deptAllot.department : '');
    return (!statusF || v.status === statusF) &&
           (!typeF   || v.type   === typeF) &&
           (!deptF   || vDept    === deptF) &&
           (!search  || v.name.toLowerCase().includes(search) ||
                        v.plate.toLowerCase().includes(search) ||
                        (v.chassis||'').toLowerCase().includes(search) ||
                        (v.designation||'').toLowerCase().includes(search));
  });
  
  const tbody = document.getElementById('vehiclesBody');
  
  const deptPill = (dept) => {
    if (!dept) return '<span style="color:var(--text-muted)">-</span>';
    const map = { general: ['General','🏢','dept-general'], sale: ['Sale','💼','dept-sale'], admin: ['Admin','🛡️','dept-admin'] };
    const [label, icon, cls] = map[dept] || [dept, '', ''];
    return `<span class="dept-pill ${cls}">${icon} ${label}</span>`;
  };
  
  const insBadge = (ins) => {
    if (ins === 'insured') return '<span class="ins-badge ins-insured">✓ Insured</span>';
    if (ins === 'expired') return '<span class="ins-badge ins-expired">⚠ Expired</span>';
    return '<span class="ins-badge ins-not">— Not Insured</span>';
  };
  
  tbody.innerHTML = list.length ? list.map((v, i) => {
    const driverName = getDriverName(v.driver);
    const deptAllot  = state.allotments.find(a => a.vehicle === v.id && a.status === 'Active');
    const dept       = v.dept || (deptAllot ? deptAllot.department : '');
    const etagIcon   = v.etag    ? '<span title="E-Tag/Token" style="color:var(--green)">✔</span>' : '<span style="color:var(--red)">✖</span>';
    const envIcon    = v.envTag  ? '<span title="Env Tag"    style="color:var(--green)">✔</span>' : '<span style="color:var(--red)">✖</span>';
    return `
      <tr ondblclick="openEditVehicle('${v.id}')" style="cursor:pointer;" title="Double click to edit">
        <td>${i+1}</td>
        <td><code style="background:var(--bg3);padding:2px 8px;border-radius:6px;font-size:0.82rem;">${v.plate}</code></td>
        <td>
          <div style="display:flex;align-items:center;gap:8px;">
            <div style="width:28px;height:28px;border-radius:6px;background:linear-gradient(135deg,var(--accent),#8b5cf6);display:flex;align-items:center;justify-content:center;font-size:1rem;flex-shrink:0;">${typeEmoji(v.type)}</div>
            <div>
              <div style="font-weight:600;font-size:0.88rem;">${v.name}</div>
              <div style="font-size:0.72rem;color:var(--text-muted);">${v.year || ''}</div>
            </div>
          </div>
        </td>
        <td><span style="font-size:0.85rem;">${v.type}</span></td>
        <td>
          <div style="font-size:0.85rem;">${v.color || '—'}</div>
          <div style="font-size:0.72rem;color:var(--text-muted);">${v.power || ''}</div>
        </td>
        <td>
          <div style="font-size:0.78rem;font-family:monospace;color:var(--text-secondary);">${v.chassis || '—'}</div>
          <div style="font-size:0.72rem;color:var(--text-muted);margin-top:2px;">${v.engine || ''}</div>
        </td>
        <td>
          <div style="font-size:0.85rem;font-weight:600;">${driverName}</div>
          <div style="font-size:0.72rem;color:var(--text-muted);">${v.empId ? 'ID: ' + v.empId + ' | ' : ''}${v.designation || ''}</div>
          ${v.allotmentDate ? `<div style="font-size:0.68rem;color:var(--accent);margin-top:2px;">📅 Allot: ${formatDate(v.allotmentDate)}</div>` : ''}
        </td>
        <td>${deptPill(dept)}</td>
        <td>${insBadge(v.insurance)}</td>
        <td style="white-space:nowrap;">
          <span title="E-Tag/Token">${etagIcon}</span>
          <span title="Env Tag" style="margin-left:4px;">${envIcon}</span>
        </td>
        <td>
          <div style="display:flex;gap:6px;">
            <button class="btn-icon edit" onclick="openEditVehicle('${v.id}')">✏ Edit</button>
            <button class="btn-icon delete" onclick="confirmDelete('vehicle','${v.id}')">🗑</button>
          </div>
        </td>
      </tr>
    `;
  }).join('') : `<tr><td colspan="11"><div class="empty-state"><div class="empty-icon">🚗</div><p>No vehicles found</p></div></td></tr>`;
}

function typeEmoji(t) {
  return {Car:'🚗',Truck:'🚛',Van:'🚐',Motorcycle:'🏍',Bus:'🚌'}[t] || '🚙';
}

