function syncMaintenanceBill(maintRec) {
  if (!state.bills) state.bills = [];
  
  let bill = state.bills.find(b => b.referenceId === maintRec.id);
  if (!bill) {
    bill = {
      id: uid(),
      referenceId: maintRec.id,
      billNo: generateNextBillNo()
    };
    state.bills.push(bill);
  }
  
  bill.date = maintRec.date;
  bill.vehicle = maintRec.vehicle;
  bill.driver = maintRec.driver;
  bill.type = 'Maintenance';
  bill.vendor = maintRec.vendor || ('Maintenance Service: ' + maintRec.type);
  bill.vendorAddress = maintRec.vendorAddress || '';
  bill.amount = maintRec.cost;
  bill.status = maintRec.status === 'Completed' ? 'Paid' : 'Pending';
  bill.notes = maintRec.notes || '';
  bill.currentReading = maintRec.currentReading || '';
  bill.nextReading = maintRec.nextReading || '';
}

