let fuelRowCount = 0;

function getVehiclesByDept(deptKey) {
  if (!deptKey) return state.vehicles;
  const deptVehicleIds = state.allotments
    .filter(a => a.department === deptKey && a.status === 'Active')
    .map(a => a.vehicle);
  // Also include vehicles with dept field matching
  return state.vehicles.filter(v => deptVehicleIds.includes(v.id) || v.dept === deptKey);
}

function buildVehicleOptions(selectedId = '', deptKey = '', searchQuery = '') {
  let vehicles = getVehiclesByDept(deptKey);
  if (searchQuery) {
    const q = searchQuery.toLowerCase().trim();
    vehicles = vehicles.filter(v => v.name.toLowerCase().includes(q) || v.plate.toLowerCase().includes(q));
  }
  return '<option value="">Select Vehicle</option>' +
    vehicles.map(v =>
      `<option value="${v.id}" ${v.id === selectedId ? 'selected' : ''}>${v.name} (${v.plate})</option>`
    ).join('');
}

