function removeFuelRow(idx) {
  const row = document.getElementById(`fuelRow-${idx}`);
  if (row) row.remove();
  updateFuelGrandTotal();
}

function recalcFuelRow(idx) {
  const row = document.getElementById(`fuelRow-${idx}`);
  if (!row) return;
  const litres = parseFloat(row.querySelector('.fuel-litres').value) || 0;
  const rate   = parseFloat(row.querySelector('.fuel-rate').value)   || 0;
  const total  = litres * rate;
  row.querySelector('.fuel-total').value = total > 0 ? Math.round(total) : '';
  
  // Calculate fuel average
  const odometerEl = row.querySelector('.fuel-odometer');
  const avgEl = row.querySelector('.fuel-average');
  const vehicleEl = row.querySelector('.fuel-vehicle');
  if (avgEl && odometerEl && vehicleEl && litres > 0) {
    const vehicleId = vehicleEl.value;
    const currentOdometer = parseFloat(odometerEl.value) || 0;
    if (vehicleId && currentOdometer > 0) {
      // Find the last fuel entry for this vehicle (before current batch)
      const prevEntries = state.fuel.filter(f => f.vehicle === vehicleId && f.odometer > 0)
                          .sort((a, b) => new Date(b.date) - new Date(a.date));
      const prevOdometer = prevEntries.length > 0 ? prevEntries[0].odometer : 0;
      if (prevOdometer > 0 && currentOdometer > prevOdometer) {
        const kmDriven = currentOdometer - prevOdometer;
        const avg = (kmDriven / litres).toFixed(2);
        avgEl.value = avg + ' km/L';
        avgEl.style.color = '#10b981';
      } else if (prevOdometer === 0) {
        avgEl.value = 'First';
        avgEl.style.color = '#94a3b8';
      } else {
        avgEl.value = '—';
        avgEl.style.color = '#94a3b8';
      }
    } else {
      avgEl.value = '—';
    }
  }
  
  updateFuelGrandTotal();
}

function updateFuelGrandTotal() {
  let grand = 0;
  document.querySelectorAll('#fuelRowsBody .fuel-total').forEach(inp => {
    grand += parseFloat(inp.value) || 0;
  });
  const el = document.getElementById('fuelGrandTotal');
  if (el) el.textContent = fmtPKR(grand);
}

