function openEditFuelBatch(batchId) {
  const batchEntries = state.fuel.filter(x => x.batchId === batchId);
  if (!batchEntries.length) return;
  editingId.fuelBatch = batchId;
  document.getElementById('fuelModalTitle').textContent = 'Edit Fuel Batch';
  document.getElementById('fuelId').value = batchId;
  document.getElementById('fuelRowsBody').innerHTML = '';
  document.getElementById('fuelGrandTotal').textContent = 'PKR 0';
  fuelRowCount = 0;
  
  batchEntries.forEach(f => {
    const rate = f.rate || (f.litres > 0 ? (f.cost / f.litres) : 0);
    addFuelRow({ vehicle: f.vehicle, driver: f.driver, fuelType: f.fuelType, date: f.date, litres: f.litres, rate: rate, cost: f.cost, odometer: f.odometer });
  });
  updateFuelGrandTotal();
  openModal('fuelModal');
}

document.getElementById('fuelForm').addEventListener('submit', e => {
  e.preventDefault();
  const rows = document.querySelectorAll('#fuelRowsBody tr');
  const batchRows = [];
  const batchId = editingId.fuelBatch || uid();

  let validationError = false;
  rows.forEach((row, i) => {
    const vehicle  = row.querySelector('.fuel-vehicle')?.value;
    const driver   = row.querySelector('.fuel-driver')?.value || '';
    const fuelType = row.querySelector('.fuel-type')?.value || 'PETROL';
    const date     = row.querySelector('.fuel-date')?.value;
    const litres   = parseFloat(row.querySelector('.fuel-litres')?.value) || 0;
    const rate     = parseFloat(row.querySelector('.fuel-rate')?.value)   || 0;
    const cost     = parseFloat(row.querySelector('.fuel-total')?.value)  || 0;
    const odometer = parseFloat(row.querySelector('.fuel-odometer')?.value) || 0;
    
    // Check if any fields in the row are filled
    const isRowEdited = vehicle || litres > 0 || rate > 0 || odometer > 0;
    if (isRowEdited) {
      if (!vehicle) {
        showToast(`Row #${i+1}: Please select a vehicle.`, 'error');
        validationError = true;
        return;
      }
      if (litres <= 0) {
        showToast(`Row #${i+1}: Litres must be greater than 0.`, 'error');
        validationError = true;
        return;
      }
      if (rate <= 0) {
        showToast(`Row #${i+1}: Rate must be greater than 0.`, 'error');
        validationError = true;
        return;
      }
      if (!date) {
        showToast(`Row #${i+1}: Please select a date.`, 'error');
        validationError = true;
        return;
      }
      const pumpName = row.querySelector('.fuel-pump')?.value?.trim() || '';
      batchRows.push({ id: uid(), batchId, vehicle, driver, fuelType, date, litres, rate, cost, odometer,
        fuelAverage: row.querySelector('.fuel-average')?.value || '',
        pumpName });
    }
  });

  if (validationError) return;
  if (batchRows.length === 0) { showToast('Please fill at least one vehicle row', 'error'); return; }

  // If editing, remove old entries for this batch
  if (editingId.fuelBatch) {
    state.fuel = state.fuel.filter(f => f.batchId !== batchId);
  }
  state.fuel.push(...batchRows);

  // Generate / Update corresponding Fuel Voucher bill
  const firstDate = batchRows[0].date;
  const grandTotal = batchRows.reduce((s, r) => s + r.cost, 0);
  // Get pump name from first filled row
  const pumpNameForBill = batchRows.find(r => r.pumpName)?.pumpName || '';
  const voucherLines = batchRows.map(r => {
    const vn = getVehicleName(r.vehicle);
    const pump = r.pumpName ? ` [${r.pumpName}]` : '';
    return `${vn}${pump}: ${r.litres}L × PKR ${r.rate}/L = PKR ${r.cost.toLocaleString()}`;
  }).join(' | ');

  // Preserve existing billNo if editing; only generate new one for new entry
  const existingBillForNo = editingId.fuelBatch ? state.bills.find(b => b.fuelBatchId === batchId || b.id === batchId) : null;
  const billNo = existingBillForNo ? existingBillForNo.billNo : generateNextBillNo();

  const fuelBill = {
    id: batchId, // Use batchId as bill id to link them easily
    billNo,
    date: firstDate,
    vehicle: batchRows[0].vehicle, // primary vehicle
    type: 'Fuel',
    vendor: pumpNameForBill ? pumpNameForBill : `Fuel Voucher (${batchRows.length} Vehicle${batchRows.length > 1 ? 's' : ''})`,
    pumpName: pumpNameForBill,
    amount: grandTotal,
    status: 'Paid',
    notes: voucherLines,
    fuelBatchId: batchId,
    fuelBatch: true,
    batchDetails: batchRows
  };

  if (editingId.fuelBatch) {
    // Update existing bill if present
    const existingBillIdx = state.bills.findIndex(b => b.fuelBatchId === batchId || b.id === batchId);
    if (existingBillIdx >= 0) {
      fuelBill.id = state.bills[existingBillIdx].id;
      fuelBill.status = state.bills[existingBillIdx].status; // preserve status
      state.bills[existingBillIdx] = fuelBill;
    } else {
      state.bills.push(fuelBill);
    }
  } else {
    state.bills.push(fuelBill);
  }

  showToast(`Fuel voucher saved ✅`, 'success');
  saveState(); closeModal('fuelModal'); renderFuel();
  if (document.getElementById('page-bills').classList.contains('active')) renderBills();
});


// ─── Delete ───
function confirmDelete(type, id) {
  deleteTarget = { type, id };
  openModal('deleteModal');
}
document.getElementById('deleteConfirmBtn').addEventListener('click', () => {
  const { type, id } = deleteTarget;
  if (type === 'vehicle')     state.vehicles     = state.vehicles.filter(x => x.id !== id);
  if (type === 'driver')      state.drivers      = state.drivers.filter(x => x.id !== id);
  if (type === 'maintenance') {
    state.maintenance  = state.maintenance.filter(x => x.id !== id);
    state.bills        = state.bills.filter(x => x.referenceId !== id);
  }
  if (type === 'fuelBatch') {
    state.fuel = state.fuel.filter(x => x.batchId !== id);
    state.bills = state.bills.filter(x => x.fuelBatchId !== id && x.id !== id);
  }
  if (type === 'allotment')   state.allotments   = state.allotments.filter(x => x.id !== id);
  if (type === 'bill')        state.bills        = state.bills.filter(x => x.id !== id);
  saveState();
  closeModal('deleteModal');
  showToast('Deleted successfully', 'success');
  renderPage(document.querySelector('.page.active').id.replace('page-', ''));
  updateDashStats();
  renderSidebarDeptVehicles();
});

