document.getElementById('globalSearch').addEventListener('input', function() {
  const q = this.value.toLowerCase().trim();
  if (!q) return;
  const matchV = state.vehicles.some(v => v.name.toLowerCase().includes(q) || v.plate.toLowerCase().includes(q));
  const matchD = state.drivers.some(d => d.name.toLowerCase().includes(q));
  if (matchV) navigate('vehicles');
  else if (matchD) navigate('drivers');
});

