// ─── Toast ───
function showToast(msg, type = 'success') {
  const t = document.getElementById('toast');
  const icon = type === 'success' ? '✅' : '❌';
  t.textContent = icon + ' ' + msg;
  t.className = 'toast show ' + type;
  setTimeout(() => { t.classList.remove('show'); }, 3000);
}

// ─── Update dashboard stats without full re-render ───
function updateDashStats() {
  document.getElementById('stat-total').textContent = state.vehicles.length;
  
  const bikeCount = state.vehicles.filter(v => v.type === 'Motorcycle').length;
  if (document.getElementById('stat-bikes')) document.getElementById('stat-bikes').textContent = bikeCount;
  
  const currentMonth = new Date().toISOString().slice(0, 7);
  const monthlyFuelCost = state.fuel.reduce((sum, f) => f.date.startsWith(currentMonth) ? sum + (f.cost || 0) : sum, 0);
  if (document.getElementById('stat-fuel-cost')) document.getElementById('stat-fuel-cost').textContent = fmtPKR(monthlyFuelCost);
  
  const pendingMaintenance = state.maintenance.filter(m => m.status === 'Pending').length;
  const maintenanceCount = pendingMaintenance > 0 ? pendingMaintenance : state.vehicles.filter(v => v.status === 'Maintenance').length;
  if (document.getElementById('stat-maintenance')) document.getElementById('stat-maintenance').textContent = maintenanceCount;
  
  const totalVehiclesBadge = document.getElementById('sidebar-total-vehicles-count');
  if (totalVehiclesBadge) totalVehiclesBadge.textContent = state.vehicles.length;

  const totalBikesBadge = document.getElementById('sidebar-bikes-count');
  if (totalBikesBadge) totalBikesBadge.textContent = bikeCount;

  const totalTokenBadge = document.getElementById('sidebar-tokentax-count');
  if (totalTokenBadge) totalTokenBadge.textContent = state.vehicles.filter(v => v.etag || v.envTag).length;
}

// ─── Notification Button ───
document.getElementById('notifBtn').addEventListener('click', () => {
  const expired = state.drivers.filter(d => d.licenseExpiry && new Date(d.licenseExpiry) < new Date());
  const maint   = state.vehicles.filter(v => v.status === 'Maintenance');
  let msgs = [];
  if (expired.length) msgs.push(`${expired.length} driver license(s) expired`);
  if (maint.length)   msgs.push(`${maint.length} vehicle(s) in maintenance`);
  if (!msgs.length)   msgs.push('All systems OK ✅');
  showToast(msgs.join(' | '), msgs.length > 1 ? 'error' : 'success');
});

// ─── DEPARTMENTS ───

function getDeptLabel(key) {
  const d = DEPARTMENTS.find(x => x.key === key);
  return d ? d.label : key;
}
function getDeptIcon(key) {
  const d = DEPARTMENTS.find(x => x.key === key);
  return d ? d.icon : '🏢';
}

// Render sidebar vehicle lists under each department
function renderSidebarDeptVehicles() {
  DEPARTMENTS.forEach(dept => {
    const container = document.getElementById('deptVehicles-' + dept.key);
    if (!container) return;
    const activeAllots = state.allotments.filter(a => a.department === dept.key);
    
    // Update count badge on department nav header
    const header = container.previousElementSibling;
    let badge = header.querySelector('.dept-count-badge');
    const activeCount = activeAllots.filter(a => a.status === 'Active').length;
    if (activeCount > 0) {
      if (!badge) {
        badge = document.createElement('span');
        badge.className = 'dept-count-badge';
        header.querySelector('.nav-label').after(badge);
      }
      badge.textContent = activeCount;
    } else if (badge) {
      badge.remove();
    }

    if (activeAllots.length === 0) {
      container.innerHTML = '<div class="dept-empty">No vehicles allotted</div>';
      return;
    }
    container.innerHTML = activeAllots.map(a => {
      const v = state.vehicles.find(x => x.id === a.vehicle);
      if (!v) return '';
      const d = state.drivers.find(x => x.id === v.driver);
      const driverName = d ? d.name : 'Unassigned';
      return `
        <div class="dept-vehicle-item" onclick="openEditVehicle('${v.id}')" style="cursor: pointer; flex-direction: column; align-items: flex-start; gap: 4px;" title="Click to view vehicle details">
          <div style="display:flex; width: 100%; align-items: center; gap: 8px;">
            <span class="dept-vehicle-dot ${a.status === 'Returned' ? 'returned' : ''}"></span>
            <span style="font-weight: 600; color: var(--accent);">${v.name}</span>
            <span class="dept-vehicle-plate">${v.plate}</span>
          </div>
          <div style="font-size: 0.72rem; color: var(--text-muted); margin-left: 14px; display: flex; align-items: center; gap: 4px;">
            <span style="font-size: 0.8rem;">👤</span> ${driverName}
          </div>
        </div>
      `;
    }).join('');
  });
}

