// Render main departments page
function renderDepartments() {
  const deptFilter   = document.getElementById('deptPageFilter').value;
  const statusFilter = document.getElementById('deptStatusFilter').value;
  const search       = document.getElementById('deptSearch').value.toLowerCase();

  // Stats
  DEPARTMENTS.forEach(d => {
    const el = document.getElementById('dept-stat-' + d.key);
    if (el) el.textContent = state.allotments.filter(a => a.department === d.key && a.status === 'Active').length;
  });
  const totalEl = document.getElementById('dept-stat-total');
  if (totalEl) totalEl.textContent = state.allotments.length;

  const area = document.getElementById('deptCardsArea');
  let html = '';

  const deptsToShow = deptFilter ? DEPARTMENTS.filter(d => d.key === deptFilter) : DEPARTMENTS;

  deptsToShow.forEach(dept => {
    let allots = state.allotments.filter(a => a.department === dept.key);
    if (statusFilter) allots = allots.filter(a => a.status === statusFilter);
    if (search) {
      allots = allots.filter(a => {
        const v = state.vehicles.find(x => x.id === a.vehicle);
        const vName = v ? v.name.toLowerCase() : '';
        const vPlate = v ? v.plate.toLowerCase() : '';
        return vName.includes(search) || vPlate.includes(search) || dept.label.toLowerCase().includes(search);
      });
    }

    html += `
      <div class="dept-section">
        <div class="dept-section-header">
          <span class="dept-section-icon">${dept.icon}</span>
          <span class="dept-section-title">${dept.label} Department</span>
          <span class="dept-section-count">${allots.length} vehicle${allots.length !== 1 ? 's' : ''}</span>
        </div>
        <div class="table-wrap">
          <table class="data-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Vehicle</th>
                <th>Plate No.</th>
                <th>Allotment Date</th>
                <th>Purpose</th>
                <th>Return Date</th>
                <th>Status</th>
                <th>Notes</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              ${allots.length ? allots.map((a, i) => {
                const v = state.vehicles.find(x => x.id === a.vehicle);
                return `
                  <tr>
                    <td>${i + 1}</td>
                    <td onclick="openEditVehicle('${v ? v.id : ''}')" style="cursor: pointer;" title="Click to view vehicle details">
                      <div style="display:flex;align-items:center;gap:10px;">
                        <div style="width:32px;height:32px;border-radius:8px;background:linear-gradient(135deg,var(--accent),#8b5cf6);display:flex;align-items:center;justify-content:center;font-size:1rem;">${v ? typeEmoji(v.type) : '🚙'}</div>
                        <strong style="color: var(--accent); text-decoration: underline;">${v ? v.name : '—'}</strong>
                      </div>
                    </td>
                    <td><code style="background:var(--bg3);padding:2px 8px;border-radius:6px;font-size:0.82rem;">${v ? v.plate : '—'}</code></td>
                    <td>${formatDate(a.date)}</td>
                    <td>${a.purpose || '—'}</td>
                    <td>${a.returnDate ? formatDate(a.returnDate) : '<span style="color:var(--text-muted)">—</span>'}</td>
                    <td>${statusBadge(a.status)}</td>
                    <td style="max-width:150px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;" title="${a.notes || ''}">${a.notes || '—'}</td>
                    <td>
                      <div style="display:flex;gap:6px;">
                        <button class="btn-icon edit" onclick="openEditAllotment('${a.id}')">✏ Edit</button>
                        <button class="btn-icon delete" onclick="confirmDelete('allotment','${a.id}')">🗑</button>
                      </div>
                    </td>
                  </tr>
                `;
              }).join('') : `<tr><td colspan="9"><div class="empty-state"><div class="empty-icon">${dept.icon}</div><p>No vehicles allotted to ${dept.label}</p></div></td></tr>`}
            </tbody>
          </table>
        </div>
      </div>
    `;
  });

  area.innerHTML = html;
}

