function renderBills() {
  if (!state.bills) state.bills = [];
  
  // Update select if empty
  const vehicleFilter = document.getElementById('billVehicleFilter');
  if (vehicleFilter && vehicleFilter.options.length <= 1) {
    populateVehicleSelects('billVehicleFilter', '');
  }

  const typeF = document.getElementById('billTypeFilter').value;
  const statusF = document.getElementById('billStatusFilter').value;
  const vehF = document.getElementById('billVehicleFilter').value;
  const search = document.getElementById('billSearch').value.toLowerCase();

  let list = state.bills.filter(b => {
    return (!typeF || b.type === typeF) &&
           (!statusF || b.status === statusF) &&
           (!vehF || b.vehicle === vehF) &&
           (!search || b.billNo.toLowerCase().includes(search) || b.vendor.toLowerCase().includes(search));
  });

  list.sort((a,b) => new Date(b.date) - new Date(a.date));

  let totalAmount = 0;
  let paidCount = 0;
  let pendingCount = 0;

  const tbody = document.getElementById('billsBody');
  if(!tbody) return;

  tbody.innerHTML = list.length ? list.map((b, i) => {
    totalAmount += Number(b.amount) || 0;
    if (b.status === 'Paid') paidCount++;
    else pendingCount++;

    const vName = getVehicleName(b.vehicle);
    
    return `
      <tr ondblclick="openInvoice('${b.id}')" style="cursor:pointer;" title="Double click to view invoice">
        <td>${i + 1}</td>
        <td><code style="background:var(--bg3);padding:2px 8px;border-radius:6px;font-size:0.82rem;">${b.billNo}</code></td>
        <td>${formatDate(b.date)}</td>
        <td><strong>${vName}</strong></td>
        <td>${b.type}</td>
        <td>${b.vendor}</td>
        <td><strong>${fmtPKR(b.amount)}</strong></td>
        <td>${statusBadge(b.status)}</td>
        <td>
          <div style="display:flex;gap:6px;">
            <button class="btn-icon" onclick="openInvoice('${b.id}')" title="View Invoice">📄</button>
            <button class="btn-icon delete" onclick="confirmDelete('bill','${b.id}')" title="Delete">🗑</button>
          </div>
        </td>
      </tr>
    `;
  }).join('') : `<tr><td colspan="9"><div class="empty-state"><div class="empty-icon">🧾</div><p>No bills found</p></div></td></tr>`;

  document.getElementById('bill-stat-total-pkr').textContent = fmtPKR(totalAmount);
  document.getElementById('bill-stat-paid').textContent = paidCount;
  document.getElementById('bill-stat-pending').textContent = pendingCount;
}

