  editingId.bill = id;
  document.getElementById('billModalTitle').textContent = 'Edit Bill Entry';
  document.getElementById('billId').value = b.id;
  document.getElementById('billNumber').value = b.billNo;
  document.getElementById('billDate').value = b.date;
  populateVehicleSelects('billVehicle', b.vehicle);
