function openInvoice(id) {
  const b = state.bills.find(x => x.id === id);
  if (!b) return;
  
  const v = state.vehicles.find(x => x.id === b.vehicle);
  const vName = v ? v.name : 'Unknown';
  const vPlate = v ? v.plate : '-';
  
  const drvObj = b.driver ? state.drivers.find(d => d.id === b.driver) : (v ? state.drivers.find(d => d.id === v.driver) : null);
  const dName = drvObj ? drvObj.name : '-';
  const drvPhone = drvObj ? (drvObj.phone || '-') : '-';
  
  // Find allotment
  const deptAllot = state.allotments.find(a => a.vehicle === b.vehicle && a.status === 'Active');
  const vDept = v ? (v.dept || (deptAllot ? deptAllot.department : '-')) : '-';
  
  const companyName = (state.settings && state.settings.companyName) || 'Vision Food & Packaging';

  if (b.fuelBatch && b.batchDetails && b.batchDetails.length > 0) {
    document.getElementById('invoiceSheet').style.display = 'none';
    document.getElementById('fuelInvoiceSheet').style.display = 'block';
    
    // Fix old random bill numbers on-the-fly for display
    let displayBillNo = b.billNo || '';
    if (!String(displayBillNo).startsWith('VFP-A-')) {
      // Assign a proper sequential number and save it
      displayBillNo = generateNextBillNo();
      b.billNo = displayBillNo;
      saveState();
    }
    
    if (document.getElementById('invBillNoFuelField')) {
      document.getElementById('invBillNoFuelField').textContent = displayBillNo;
    }
    if (document.getElementById('invBillDateFuelField')) {
      document.getElementById('invBillDateFuelField').textContent = formatDate(b.date);
    }
    
    // Show pump name if available
    const pumpNameEl = document.getElementById('invPumpNameFuelField');
    const pumpNameRow = document.getElementById('invPumpNameRow');
    const pumpName = b.pumpName || (b.batchDetails && b.batchDetails.find(r => r.pumpName)?.pumpName) || '';
    if (pumpNameEl && pumpNameRow) {
      if (pumpName) {
        pumpNameEl.textContent = pumpName;
        pumpNameRow.style.display = 'block';
      } else {
        pumpNameRow.style.display = 'none';
      }
    }
    
    let tbodyHtml = '';
    b.batchDetails.forEach((r) => {
      const vObj = state.vehicles.find(x => x.id === r.vehicle);
      const vPlate = vObj ? vObj.plate : '-';
      const rateStr = parseFloat(r.rate || 0).toFixed(2);
      
      tbodyHtml += `<tr style="border-bottom:1px solid #cbd5e1;">
        <td style="padding:10px; border:1px solid #cbd5e1; color:#0f172a;">${formatDate(r.date)}</td>
        <td style="padding:10px; border:1px solid #cbd5e1; font-weight:700; color:#1e3a8a;">${vPlate}</td>
        <td style="padding:10px; border:1px solid #cbd5e1; color:#0f172a;">${r.fuelType || 'PETROL'}</td>
        <td style="padding:10px; border:1px solid #cbd5e1; text-align:right; color:#0f172a;">${parseFloat(r.litres).toFixed(2)}</td>
        <td style="padding:10px; border:1px solid #cbd5e1; text-align:right; color:#0f172a;">${rateStr}</td>
        <td style="padding:10px; border:1px solid #cbd5e1; text-align:right; font-weight:700; color:#1e3a8a;">PKR ${Number(r.cost).toLocaleString()}</td>
      </tr>`;
    });
    
    document.getElementById('fuelInvoiceBodySimple').innerHTML = tbodyHtml;
    document.getElementById('fuelInvoiceGrandTotalSimple').textContent = fmtPKR(b.amount);
    
    // Status Stamp for Fuel Invoice
    const stampFuel = document.getElementById('invStampFuelSimple');
    if (stampFuel) {
      stampFuel.textContent = b.status === 'Paid' ? 'PAID' : 'PENDING';
      stampFuel.style.borderColor = b.status === 'Paid' ? '#22c55e' : '#f97316';
      stampFuel.style.color = b.status === 'Paid' ? '#22c55e' : '#f97316';
    }
  } else {
    document.getElementById('fuelInvoiceSheet').style.display = 'none';
    document.getElementById('invoiceSheet').style.display = 'block';

    document.getElementById('invCompanyNameSimple').textContent = companyName;
    document.getElementById('invCompanyNameField').textContent = companyName;
    document.getElementById('invVehPlateField').textContent = vPlate;
    document.getElementById('invDriverNameField').textContent = dName;
    document.getElementById('invDriverPhoneField').textContent = drvPhone;
    document.getElementById('invVendorNameField').textContent = b.vendor;
    document.getElementById('invVendorAddressField').textContent = b.vendorAddress || 'Lahore, Pakistan';
    
    document.getElementById('invBillNoField').textContent = b.billNo;
    document.getElementById('invBillDateField').textContent = formatDate(b.date);
    document.getElementById('invBillTypeField').textContent = b.type;
    
    document.getElementById('invCurrentReadingField').textContent = b.currentReading || '0';
    document.getElementById('invNextReadingField').textContent = b.nextReading || '0';
    
    document.getElementById('invDescField').textContent = b.vendor;
    document.getElementById('invDetailsField').textContent = b.notes || '-';
    document.getElementById('invAmountField').textContent = fmtPKR(b.amount);
    document.getElementById('invTotalField').textContent = fmtPKR(b.amount);

    // Status Stamp for Standard Invoice
    const stamp = document.getElementById('invStampSimple');
    if (stamp) {
      stamp.textContent = b.status === 'Paid' ? 'PAID' : 'PENDING';
      stamp.style.borderColor = b.status === 'Paid' ? '#22c55e' : '#f97316';
      stamp.style.color = b.status === 'Paid' ? '#22c55e' : '#f97316';
    }
  }
  
  openModal('invoiceModal');
  
  // Track currently open bill for markInvoicePaid
  _currentInvoiceBillId = b.id;
  const paidBtn = document.getElementById('markPaidBtn');
  if (paidBtn) paidBtn.textContent = b.status === 'Paid' ? '↩ Mark as Pending' : '✅ Mark as Paid';
}

function printInvoiceSheet() {
  window.print();
}

// Track which bill is currently open in the invoice modal
let _currentInvoiceBillId = null;

function openInvoiceTracked(id) {
  _currentInvoiceBillId = id;
}

function markInvoicePaid() {
  if (!_currentInvoiceBillId) return;
  const b = state.bills.find(x => x.id === _currentInvoiceBillId);
  if (!b) return;
  
  const newStatus = b.status === 'Paid' ? 'Pending' : 'Paid';
  b.status = newStatus;
  saveState();
  
  // Update stamps in the open modal
  const isPaid = newStatus === 'Paid';
  const color = isPaid ? '#22c55e' : '#f97316';
  const label = isPaid ? 'PAID' : 'PENDING';
  
  ['invStampSimple', 'invStampFuelSimple'].forEach(id => {
    const el = document.getElementById(id);
    if (el) {
      el.textContent = label;
      el.style.borderColor = color;
      el.style.color = color;
    }
  });
  
  // Update the Mark as Paid button text
  const btn = document.getElementById('markPaidBtn');
  if (btn) btn.textContent = isPaid ? '↩ Mark as Pending' : '✅ Mark as Paid';
  
  // Refresh bills table if visible
  if (document.getElementById('page-bills')?.classList.contains('active')) renderBills();
  showToast(`Bill marked as ${newStatus}! ✅`, 'success');
}


