document.getElementById('settingsFirebaseForm')?.addEventListener('submit', e => {
  e.preventDefault();
  const config = {
    apiKey: document.getElementById('fbApiKey').value.trim(),
    authDomain: document.getElementById('fbAuthDomain').value.trim(),
    databaseURL: document.getElementById('fbDatabaseURL').value.trim(),
    projectId: document.getElementById('fbProjectId').value.trim()
  };
  
  if (!state.settings.firebase) state.settings.firebase = {};
  state.settings.firebase = config;
  saveState();
  initFirebaseSync(config);
});

function initFirebaseSync(config) {
  if (window.firebaseInitialized) return;
  if (!config.apiKey || !config.databaseURL || !config.projectId) return;

  showToast('Connecting to Cloud Sync...', 'info');

  const s1 = document.createElement('script');
  s1.src = 'https://www.gstatic.com/firebasejs/8.10.1/firebase-app.js';
  const s2 = document.createElement('script');
  s2.src = 'https://www.gstatic.com/firebasejs/8.10.1/firebase-database.js';

  s1.onload = () => {
    document.head.appendChild(s2);
  };

  s2.onload = () => {
    try {
      firebase.initializeApp(config);
      const db = firebase.database();
      const stateRef = db.ref('fleet_state');

      stateRef.on('value', (snapshot) => {
        const remoteState = snapshot.val();
        if (remoteState) {
          if (JSON.stringify(state) !== JSON.stringify(remoteState)) {
            state = remoteState;
            localStorage.setItem('vehiclehub_v5', JSON.stringify(state));
            updateDashStats();
            const activePage = document.querySelector('.page.active')?.id.replace('page-', '') || 'dashboard';
            renderPage(activePage);
            showToast('Portal synced automatically! 🔄', 'success');
          }
        }
      });

      window.firebaseInitialized = true;
      window.firebaseDbRef = stateRef;
      showToast('Cloud Sync Connected successfully! 🌐', 'success');
    } catch (err) {
      console.error(err);
      showToast('Firebase connection failed: ' + err.message, 'error');
    }
  };

  document.head.appendChild(s1);
}

function disableFirebaseSync() {
  if (!confirm('Are you sure you want to disable Cloud Sync? Your portal will only store data locally.')) return;
  
  state.settings.firebase = {
    apiKey: '',
    authDomain: '',
    databaseURL: '',
    projectId: ''
  };
  saveState();
  
  document.getElementById('fbApiKey').value = '';
  document.getElementById('fbAuthDomain').value = '';
  document.getElementById('fbDatabaseURL').value = '';
  document.getElementById('fbProjectId').value = '';
  
  showToast('Cloud Sync disabled. Please reload the page to completely disconnect.', 'warning');
}

function restoreAutoBackup() {
  const backupStr = localStorage.getItem('vehiclehub_v5_auto_backup');
  if (!backupStr) {
    showToast('No auto-backup found in memory.', 'error');
    return;
  }
  try {
    const parsed = JSON.parse(backupStr);
    const count = parsed.vehicles ? parsed.vehicles.length : 0;
    if (confirm(`A protected Auto-Backup was found with ${count} vehicles.\n\nAre you sure you want to restore it? This will replace your current data.`)) {
      state = parsed;
      saveState();
      loadState();
      showToast('Auto-backup restored successfully! ✅', 'success');
      setTimeout(() => location.reload(), 1500);
    }
  } catch(e) {
    showToast('Error reading backup ❌', 'error');
  }
}

function exportAppData() {
  const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(state, null, 2));
  const downloadAnchor = document.createElement('a');
  downloadAnchor.setAttribute("href", dataStr);
  downloadAnchor.setAttribute("download", `vehiclehub_backup_${new Date().toISOString().split('T')[0]}.json`);
  document.body.appendChild(downloadAnchor);
  downloadAnchor.click();
  downloadAnchor.remove();
  showToast('Backup file downloaded successfully! 📥', 'success');
}

function importAppData(event) {
  const file = event.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    try {
      const parsed = JSON.parse(e.target.result);
      if (parsed.vehicles && parsed.drivers) {
        state = parsed;
        saveState();
        loadState();
        showToast('Data imported successfully! ✅', 'success');
        navigate('dashboard');
      } else {
        showToast('Invalid backup file structure ❌', 'error');
      }
    } catch (err) {
      showToast('Error parsing file ❌', 'error');
    }
  };
  reader.readAsText(file);
}

function resetAppData() {
  if (confirm('Are you sure you want to delete all app data? This cannot be undone.')) {
    localStorage.removeItem('vehiclehub_v5');
    sessionStorage.removeItem('fms_logged_in');
    location.reload();
  }
}

// ─── LOGIN SECURITY LOGIC ───
function checkLogin() {
  if (sessionStorage.getItem('fms_logged_in') === 'true') {
    const screen = document.getElementById('loginScreen');
    if (screen) screen.style.display = 'none';
  }
}

document.getElementById('loginForm')?.addEventListener('submit', e => {
  e.preventDefault();
  const user = document.getElementById('loginUsername').value.trim();
  const pass = document.getElementById('loginPassword').value.trim();
  const correctUser = state.settings.username || 'admin';
  const correctPass = state.settings.password || 'admin123';
  
  if (user === correctUser && pass === correctPass) {
    sessionStorage.setItem('fms_logged_in', 'true');
    const screen = document.getElementById('loginScreen');
    if (screen) screen.style.display = 'none';
    showToast('Login successful! Welcome back 🔓', 'success');
  } else {
    const errorEl = document.getElementById('loginError');
    if (errorEl) errorEl.style.display = 'block';
  }
});

